// ReversalModal.js - Modal para revertir transacciones
// Incluye política de reversión, estadísticas y lista de transacciones reversibles

import React, { useState } from 'react';
import './Modals.css';

const ReversalModal = ({ isOpen, onClose, onConfirm, transaction, transactions, stats }) => {
  const [selectedTransactionId, setSelectedTransactionId] = useState(transaction?.id || '');
  
  if (!isOpen) return null;
  
  // Si viene una transacción específica (desde el historial), usarla
  // Si no, mostrar lista de reversibles para seleccionar
  const hasSpecificTransaction = !!transaction;
  const reversibleTransactions = transactions || [];
  const selectedTransaction = hasSpecificTransaction 
    ? transaction 
    : reversibleTransactions.find(t => t.id === selectedTransactionId);
  
  const formatCurrency = (value) => {
    return new Intl.NumberFormat('es-CO', {
      style: 'currency',
      currency: 'COP',
      minimumFractionDigits: 0,
      maximumFractionDigits: 0
    }).format(value);
  };
  
  const handleSubmit = (e) => {
    e.preventDefault();
    if (!selectedTransaction && !hasSpecificTransaction) {
      alert('Selecciona una transacción para revertir');
      return;
    }
    
    onConfirm({
      transaction: selectedTransaction,
      reversalDate: new Date().toISOString()
    });
    
    onClose();
  };
  
  return (
    <div className="modal-overlay" onClick={onClose}>
      <div className="modal-content modal-reversal" onClick={(e) => e.stopPropagation()}>
        <div className="modal-header modal-reversal-header">
          <div className="reversal-icon-wrapper">
            <span className="reversal-icon">↩️</span>
          </div>
          <h2>Reversión de Transacciones</h2>
          <button className="modal-close" onClick={onClose}>×</button>
        </div>
        
        <div className="modal-body">
          {/* Política de Reversión */}
          <div className="reversal-policy-card">
            <h3>Política de Reversión</h3>
            <p>
              Puedes revertir transacciones completadas dentro de las 24 horas siguientes. 
              La reversión es instantánea y gratuita. Los puntos ganados serán descontados.
            </p>
          </div>
          
          {/* Estadísticas */}
          <div className="reversal-stats-modal">
            <div className="reversal-stat-modal">
              <span className="stat-value">{stats?.available || 0}</span>
              <span className="stat-label">Reversiones Disponibles</span>
              <span className="stat-sub">Últimas 24 horas</span>
            </div>
            <div className="reversal-stat-modal">
              <span className="stat-value">{stats?.monthlyReversals || 0}</span>
              <span className="stat-label">Reversiones Este Mes</span>
              <span className="stat-sub">Procesadas exitosamente</span>
            </div>
            <div className="reversal-stat-modal">
              <span className="stat-value">{stats?.successRate || 0}%</span>
              <span className="stat-label">Tasa de Éxito</span>
              <span className="stat-sub">Todas completadas</span>
            </div>
          </div>
          
          {/* Lista de transacciones reversibles (si no hay una específica) */}
          {!hasSpecificTransaction && (
            <div className="reversible-list-modal">
              <h3>Transacciones Reversibles</h3>
              {reversibleTransactions.length > 0 ? (
                <div className="reversible-items">
                  {reversibleTransactions.map(t => (
                    <div 
                      key={t.id} 
                      className={`reversible-item-modal ${selectedTransactionId === t.id ? 'selected' : ''}`}
                      onClick={() => setSelectedTransactionId(t.id)}
                    >
                      <div className="reversible-info-modal">
                        <div className="reversible-icon-modal">
                          {t.type === 'recarga' ? '📥' : t.type === 'transferencia' ? '🔄' : '📤'}
                        </div>
                        <div className="reversible-details">
                          <p className="reversible-desc-modal">{t.description}</p>
                          <span className="reversible-date-modal">{t.date}</span>
                        </div>
                      </div>
                      <div className="reversible-amount-modal">
                        <span className="amount-value">{formatCurrency(t.amount)}</span>
                        <span className="points-value">+{t.points} pts</span>
                      </div>
                      {selectedTransactionId === t.id && (
                        <div className="selected-check">✓</div>
                      )}
                    </div>
                  ))}
                </div>
              ) : (
                <div className="empty-reversible-modal">
                  <p>No hay transacciones reversibles en este momento</p>
                  <span>Solo puedes revertir transacciones de las últimas 24 horas</span>
                </div>
              )}
            </div>
          )}
          
          {/* Detalles de la transacción seleccionada */}
          {selectedTransaction && (
            <div className="reversal-details-card">
              <h4>Transacción a revertir</h4>
              <div className="details-row">
                <span className="detail-label">Fecha:</span>
                <span className="detail-value">{selectedTransaction.date}</span>
              </div>
              <div className="details-row">
                <span className="detail-label">Descripción:</span>
                <span className="detail-value">{selectedTransaction.description}</span>
              </div>
              <div className="details-row">
                <span className="detail-label">Monto:</span>
                <span className="detail-value highlight">{formatCurrency(selectedTransaction.amount)}</span>
              </div>
              <div className="details-row">
                <span className="detail-label">Puntos a descontar:</span>
                <span className="detail-value warning">{selectedTransaction.points} puntos</span>
              </div>
            </div>
          )}
          
          {/* Consecuencias */}
          <div className="reversal-consequences">
            <p className="consequences-title">⚠️ Al revertir esta transacción:</p>
            <ul>
              <li>El saldo de la billetera se restaurará</li>
              <li>Los puntos generados serán descontados</li>
              <li>La transacción quedará marcada como "Reversada"</li>
            </ul>
          </div>
        </div>
        
        <div className="modal-buttons reversal-buttons">
          <button type="button" className="btn-cancel" onClick={onClose}>
            Cancelar
          </button>
          <button 
            type="button" 
            className="btn-reverse-modal"
            onClick={handleSubmit}
            disabled={!selectedTransaction && !hasSpecificTransaction}
          >
            Confirmar Reversión
          </button>
        </div>
      </div>
    </div>
  );
};

export default ReversalModal;
